#include "nvs_prefs.h"
static Preferences prefs;
void nvs_setup(){prefs.begin("parakram",false);Serial.println("[nvs] OK");}
void nvs_put_int(const char*k,int v){prefs.putInt(k,v);}
int nvs_get_int(const char*k,int d){return prefs.getInt(k,d);}
void nvs_put_float(const char*k,float v){prefs.putFloat(k,v);}
float nvs_get_float(const char*k,float d){return prefs.getFloat(k,d);}
void nvs_put_string(const char*k,const char*v){prefs.putString(k,v);}
String nvs_get_string(const char*k,const char*d){return prefs.getString(k,d);}
